(function () {
  var params = new URLSearchParams(window.location.search);
  var query = params.get("q") || "";
  var input = document.querySelector("[data-search-input]");
  var box = document.querySelector("[data-search-results]");
  var title = document.querySelector("[data-search-title]");

  if (input) {
    input.value = query;
  }

  function escapeHtml(value) {
    return String(value || "").replace(/[&<>"']/g, function (char) {
      return {
        "&": "&amp;",
        "<": "&lt;",
        ">": "&gt;",
        "\"": "&quot;",
        "'": "&#39;"
      }[char];
    });
  }

  function render(items) {
    if (!box) {
      return;
    }

    box.innerHTML = items.slice(0, 120).map(function (item) {
      var tags = (item.tags || []).slice(0, 3).map(function (tag) {
        return "<span>" + escapeHtml(tag) + "</span>";
      }).join("");

      return [
        "<article class=\"movie-card compact\">",
        "<a class=\"poster\" href=\"" + escapeHtml(item.url) + "\">",
        "<img src=\"" + escapeHtml(item.cover) + "\" alt=\"" + escapeHtml(item.title) + "\" loading=\"lazy\" onerror=\"this.style.display='none'\">",
        "<span class=\"poster-year\">" + escapeHtml(item.year) + "</span>",
        "</a>",
        "<div class=\"card-body\">",
        "<a class=\"card-title\" href=\"" + escapeHtml(item.url) + "\">" + escapeHtml(item.title) + "</a>",
        "<p class=\"card-meta\">" + escapeHtml(item.region) + " · " + escapeHtml(item.type) + " · " + escapeHtml(item.genre) + "</p>",
        "<p class=\"card-desc\">" + escapeHtml(item.desc) + "</p>",
        "<div class=\"tag-row\">" + tags + "</div>",
        "</div>",
        "</article>"
      ].join("");
    }).join("");
  }

  if (query && box) {
    var normalized = query.trim().toLowerCase();
    var results = (window.SEARCH_MOVIES || []).filter(function (item) {
      return [item.title, item.region, item.type, item.year, item.genre, (item.tags || []).join(" "), item.desc]
        .join(" ")
        .toLowerCase()
        .indexOf(normalized) !== -1;
    });

    if (title) {
      title.textContent = results.length ? "搜索结果" : "未找到相关影片";
    }

    render(results);
  }
})();
